mapper.select:
SELECT id, admission_no, patient_id, department_id, attending_doctor_id, bed_id,
       admitted_at, discharged_at, discharge_type, prepaid_balance, status
FROM admissions

    AND patient_id = #{patientId}
    AND attending_doctor_id = #{doctorId}

ORDER BY admitted_at DESC, id DESC

SELECT a.id, a.admission_no AS admissionNo, a.patient_id AS patientId, a.department_id AS departmentId, a.attending_doctor_id AS attendingDoctorId, a.bed_id AS bedId, a.admitted_at AS admittedAt, a.discharged_at AS dischargedAt, a.discharge_type AS dischargeType, a.prepaid_balance AS prepaidBalance, a.status, p.name AS patientName, d.name AS departmentName, doc.name AS doctorName, b.bed_no AS bedNo FROM admissions a LEFT JOIN patients p ON a.patient_id = p.id LEFT JOIN departments d ON a.department_id = d.id LEFT JOIN doctors doc ON a.attending_doctor_id = doc.id LEFT JOIN beds b ON a.bed_id = b.id
AND a.patient_id = #{patientId} AND a.attending_doctor_id = #{doctorId}
ORDER BY a.admitted_at DESC, a.id DESC
